fn handle_coordinator_register(
    req: Request,
    coordinator: &Arc<Coordinator>,
    registry: &Arc<FormatRegistry>,
) -> Response {
    let params: CoordinatorRegisterParams = match parse_params(&req.params) {
        Ok(p) => p,
        Err(e) => return Response::error(req.id, ERR_INVALID_PARAMS, e),
    };
    let path = Path::new(&params.path);
    // Optional: warn if handler not known in registry
    let tracking_id = match coordinator.register_external(path, &params.handler) {
        Ok(id) => id,
        Err(e) => return Response::error(req.id, ERR_INTERNAL, e.to_string()),
    };
    let result = CoordinatorRegisterResult {
        tracking_id,
        status: "registered".to_string(),
    };
    let cwd = std::env::current_dir().unwrap_or_else(|_| PathBuf::from("."));
    let resp = Response::ok(req.id, serde_json::to_value(result).unwrap_or_default());
    inject_digest(resp, coordinator, &cwd)
}
```

